	.TITLE	ICONEPP	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	BIOS		; df basic input/output	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df drivers	.INS	ICODEF	.REV	ICOREV,ICOVERS		     ^ Undefined symbol	.IF	SM100		    ^ Undefined symbol	.CODE	800,11,B'111,20,2000,20,2000,2,'N,'E,'F,07	.ELSE	     ^ If/endif over/underflow	.CODE	800,11,B'111,20,2000,20,2000,2,'N,'E,'F,12	.ENDIF	      ^ If/endif over/underflow; Programme; ---------	.LOC	0START:	LIB	?OPELIB		; ouvre la librairie	LOAD.W	D3,#2		; D3 <-- souris par le clavier	LIB	?MOUSE		; utilise les 3 boutons souris	LOAD.L	D4,#LGVAR	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM		; demande mmoire pour var.	JUMP,NE	FATERR	LOAD.L	A6,A4		; A6 <-- ^variables10$:	CLR.B	(A4+)		; variables <-- zro	DEC.L	D4	JUMP,NE	10$	.IF	~CLE		   ^ Undefined symbol	LOAD.L	A4,#(A6)+ONAMEI	LIB	?SKPNAM		; A3 <-- cherche nom aprs "ICONE"	JUMP',EQ 20$		; dans la ligne de commande	LOAD.L	A3,#R16"NAMDEF			     ^ Symbol multi-defined20$:	LOAD.B	D3,(A3+)	JUMP',EQ 25$	COMP.B	D3,#CR	JUMP',EQ 25$	COMP.B	D3,#SPACE	JUMP',EQ 25$	COMP.B	D3,#'/	JUMP',EQ 25$	LOAD.B	(A4+),D3	JUMP	20$25$:	CLR.B	(A4)	LOAD.L	A3,#(A6)+ONAMEI	LOAD.L	A4,#R16"EXTDEF	CLR.W	D3	 .W	LIB,?ADDEXT	; ajoute .ICONE si pas d'autre extension		   ^ Macro symbol illegal here	.ENDIF	      ^ If/endif over/underflow	GESMEM	?ARGLGM		; D4 <-- total, D5 <-- user	COMP.L	D4,#2^18	; plus de 256 Kbytes ?	SET.B,HI (A6)+OBIG	; oui => big			 ^ Undefined symbol	.IF	CLE		  ^ Undefined symbol	NTREL	?GETPRIO	; D4 <-- priorit du CLE	DEC.B	D4		; fils plus prioritaire !	AND.W	D4,#H'FF	LOAD.L	A5,#R16"PFILS1	LOAD.L	A3,#R16"NFILS1	LOAD.L	D5,#400		; D5 <-- lg stack	NTREL	?CRETASK	; cre processus CLE1_CONTROL	.ENDIF	      ^ If/endif over/underflowEXECUTE:	TEST.B	(A6)+OBIG	; big mmoire ?			^ Undefined symbol	JUMP',T 10$		; oui => 10$	CALL	OVKILL		; libre l'overlay10$:	LIB	?OEXECUTE	; excute qq chose ...	TEST.B	(A6)+OBIG	; big mmoire ?			^ Undefined symbol	JUMP',T 30$		; oui => 30$	LOAD.W	D4,D7	CALL	OVLOAD		; recharge l'overlay	JUMP',NE FOVERR	LOAD.W	D7,D430$:	LOAD.L	A0,(A6)+OADROV			     ^ Undefined symbol	ADD.L	A0,#8	JUMP	(A0)		; puis saute retour excutionFOVERR:	PUSH.W	D7	LIB	?AFTIM	.B	EOP,NOCURS,CR,CR	.ASCIZ	/Fichier /	.EVEN	LOAD.L	A3,#R16"OVNAME			     ^ Symbol multi-defined	LIB	?AFTEXT	LIB	?AFTIM	.ASCIZ	/ --<'>> /	.EVEN	POP.W	D7FATERR:	PUSH.W	D7	LOAD.B	D3,#BIPFAT	LIB	?BEEP	POP.W	D7	LIB	?AFERROR	; affiche l'erreur	.IF	CLE		  ^ Undefined symbol	LIB	?AFTIM	.B	CR,CR	.ASCIZ	"Veuillez redmarrer le Smaky"	.EVEN20$:	LIB	?GETCAR		; attend toujours ...	JUMP	20$	.ELSE	     ^ If/endif over/underflow	LOAD.W	D4,#50*10	NTREL	?SETTIM	LIB	?GETCAR		; attend une touche ...	LOAD.W	D4,#-1	NTREL	?SETTIM	.ENDIF	      ^ If/endif over/underflowQUITTE:	LOAD.B	D3,#EOP	LIB	?AFCAR		; efface toute la fentre	LIB	?CLOLIB		; ferme la librairie	FOS	?STOP		; avorte le processus ...;--------\; OVLOAD  >;========/; Charge l'overlay.; in	-; out	D7.W	erreur; mod	D7.WOVLOAD:	PUSHM.L	D1,D4,A3,A4,A5	.IF	CLE		  ^ Undefined symbol	LOAD.L	D4,#LGRESM	; D4 <-- longueur rserve			 ^ Undefined symbol	LOAD.W	D1,#MTYPCP	; D1 <-- type compte	GESMEM	?GETMEM		; rserve qq bytes !	JUMP,NE 90$	LOAD.L	A5,A4		; A5 <-- ^rserve	.ENDIF	      ^ If/endif over/underflow10$:	LOAD.L	A3,#R16"OVNAME	; A3 <-- ^nom de l'overlay			     ^ Symbol multi-defined	FOS	?LOAD		; charge l'overlay en mmoire		     ^ Undefined symbol	JUMP,EQ 70$		; ok => 70$				; erreur =>	COMP.W	D7,#ERUNNI	; unit pas initialise ?	JUMP',EQ 20$		; oui => 20$	COMP.W	D7,#ERFDNE	; fichier n'existe pas ?	JUMP',EQ 30$		; oui => 30$	LOAD.W	D4,D7	AND.W	D4,#H'FF00	; D4 <-- catgorie de l'erreur	COMP.W	D4,#ERMM	; erreur avec le floppy ?	JUMP',EQ 40$		; oui => 40$	JUMP	90$		; autre erreur => 90$20$:	LOAD.L	A3,#R16"NAMFL0	; A3 <-- ^nom floppy 0	FOS	?ENTER		; fait un "ENTER $FLO_0"	JUMP,EQ	10$	JUMP'	40$30$:	LOAD.L	A3,#R16"NAMFL0	; A3 <-- ^nom floppy 0	FOS	?RELEASE	; fait un "RELEASE $FLO_0"40$:	LIB	?BUZZ		; grande sonnerie	LIB	?AFTIM	.B	EOP,NOCURS,CR,CR,CR	.ASCII	"Insrez une disquette systme PSos rvision "	.B	ICOREV+'0,'.		     ^ Undefined symbol	.IF	ICOVERS<10		      ^ Undefined symbol	.B	ICOVERS+'0		      ^ Undefined symbol	.ELSE	     ^ If/endif over/underflow	.B	(ICOVERS/10)+'0,(ICOVERS-((ICOVERS/10)*10))+'0		       ^ Undefined symbol	.ENDIF	      ^ If/endif over/underflow	.ASCII	" dans le floppy zro,<CR>"	.ASCIZ	"puis appuyez sur la barre d'espace ..."	.EVEN45$:	LIB	?GETCAR		; attend espace ...	COMP.W	D3,#SPACE	JUMP,NE	45$	LOAD.B	D3,#EOP	LIB	?AFCAR		; efface toute la fentre	LOAD.L	A3,#R16"NAMFL0	; A3 <-- ^nom floppy 0	FOS	?ENTER		; fait un "ENTER $FLO_0"	JUMP,NE	40$	JUMP	10$70$:	LOAD.L	(A6)+OADROV,A4			  ^ Undefined symbol	.IF	CLE		  ^ Undefined symbol	LOAD.L	A4,A5		; A4 <-- ^rserve	GESMEM	?GIVMEM		; libre la rserve	.ENDIF	      ^ If/endif over/underflow90$:	POPM.L	D1,D4,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;--------\; OVKILL  >;========/; Libre l'overlay.; in	-; out	-; mod	D7.WOVKILL:	PUSHM.L	D1,D4,A4	LOAD.L	A4,(A6)+OADROV			     ^ Undefined symbol	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM	POPM.L	D1,D4,A4	RET	.IF	CLE		  ^ Undefined symbol; Processus fils; --------------; Processus de gestion des touches (M0), (M1) et (M3).NFILS1:	.ASCIZ /CLE1_CONTROL/	.EVENPFILS1:	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer pour commande	LOAD.B	(A4)+0,#KEYSIP	; rserve inter-programmes	LOAD.B	(A4)+1,#M3&H'7F	; touche (M3) selon pseudo-code	LOAD.B	(A4)+2,#KEYSIP	; rserve inter-programmes	LOAD.B	(A4)+3,#M0&H'7F	; touche (M0) selon pseudo-code	LOAD.B	(A4)+4,#KEYSIP	; rserve inter-programmes	LOAD.B	(A4)+5,#M1&H'7F	; touche (M1) selon pseudo-code	CLR.B	(A4)+6		; termine les commandes	LIB	?GCHKEY		; D6 <-- canal clavier	LOAD.W	D3,#TYPKEY	; D3 <-- type driver clavier	FOS	?COMMAND	; donne commande d'assignation10$:	LIB	?GCHKEY		; D6 <-- canal du clavier	FOS	?GETTYPE	; D2 <-- no driver  D3 <-- type	BIOS	?WFSKEY		; wait for special key ...	COMP.B	D3,#M3	JUMP',EQ 20$	COMP.B	D3,#M3+SHIFT	JUMP',EQ 30$	COMP.B	D3,#M3+CTRL	JUMP,EQ	40$	LOAD.L	A3,#R16"NAMFL0	; A3 <-- ^nom floppy 0	COMP.B	D3,#M0	JUMP,EQ	50$	LOAD.L	A3,#R16"NAMFL1	; A3 <-- ^nom floppy 1	COMP.B	D3,#M1	JUMP,EQ	50$	JUMP	10$20$:				; (M3) =>	FOS	?OPINFO		; A4 <-- ^SYS_INFO	LOAD.B	D3,(A4)+OINLEV	; D3 <-- niveau d'aide	CLR.W	D4		; D4 <-- pas de mise  jour	FOS	?CLINFO		; ferme SYS_INFO	TEST.B	D3		; niveau d'aide pour dbutant ?	JUMP,NE	90$		; oui => 90$	LOAD.W	D3,D2		; D3 <-- no de clavier du CLE	LIB	?ASSKEY		; assigne le clavier au CLE	JUMP,NE 90$		; si erreur => 90$				; si ok =>	LOAD.B	D3,#BIPBIG	LIB	?BEEP		; on est dans le CLE (youpie)	JUMP	10$30$:				; (SHIFT-M3) =>	TSET.B	(A6)+OFLAGS:#BPDUMP ; dump en cours ?				  ^ Undefined symbol	JUMP',BS 90$		; oui => 90$	LOAD.W	D4,#4	LOAD.L	A5,#R16"PFILS3	LOAD.L	A3,#R16"NFILS3	LOAD.L	D5,#300		; D5 <-- lg stack	NTREL	?CRETASK	; cre processus CLE3_CONTROL	JUMP',NE 90$		; erreur => 90$	JUMP	10$		; ok => 10$40$:				; (CTRL-M3) =>	LOAD.L	A3,#R16"NAMPRI	LIB	?GETUPH		; A4 <-- ^nom physique	JUMP',NE 90$	LOAD.L	A3,A4	INC.L	A3		; A3 <-- saute le "$"	BIOS	?NAMDRIV	; D2 <-- numro du driver	JUMP',NE 90$	BIOS	?DAVOTR		; avorte transfert	JUMP,EQ	10$50$:				; (M0) ou (M1) =>	FOS	?RELEASE	; tente un "release"	JUMP,EQ	10$		; ok => 10$	COMP.W	D7,#ERUNNI	JUMP',NE 90$	FOS	?ENTER		; tente un "enter"	JUMP,EQ	10$		; ok => 10$90$:	LOAD.B	D3,#BIPERR	; erreur =>	LIB	?BEEP		; signal qq chose rat !	JUMP	10$; Processus effectuant un dump de la partie visible.NFILS3:	.ASCIZ /CLE3_CONTROL/	.EVENPFILS3:	LOAD.B	D3,#-1		; D3 <-- dump partie visible	LIB	?PDUMP		; effectue un dump ...	JUMP',EQ 90$	LOAD.B	D3,#BIPERR	LIB	?BEEP90$:	TCLR.B	(A6)+OFLAGS:#BPDUMP ; dump termin				  ^ Undefined symbol	NTREL	?ABORT	.ENDIF	      ^ If/endif over/underflow; Textes; ------	.IF	SM100		    ^ Undefined symbolNAMDEF:	.ASCIZ	"@:#MM0:100_ICONE.LIST"       ^ Multiple ass.	.ELSE	     ^ If/endif over/underflowNAMDEF:	.ASCIZ	"@:#MM0:SYS_ICONE.LIST"       ^ Multiple ass.	.ENDIF	      ^ If/endif over/underflowEXTDEF:	.ASCIZ	".ICONE"	.IF	CLE		  ^ Undefined symbol	.IF	SM100		    ^ Undefined symbolOVNAME:	.ASCIZ	/@:#MM0:100_CLE.BIN/       ^ Multiple ass.	.ELSE	     ^ If/endif over/underflowOVNAME:	.ASCIZ	/@:#MM0:SYS_CLE.BIN/       ^ Multiple ass.	.ENDIF	      ^ If/endif over/underflow	.ELSE	     ^ If/endif over/underflowOVNAME:	.ASCIZ	/@:#MM0:ICONE.BIN/       ^ Multiple ass.	.ENDIF	      ^ If/endif over/underflow	.IF	CLE		  ^ Undefined symbolNAMPRI:	.ASCIZ	/#PRINTER/	; nom logique imprimante	.ENDIF	      ^ If/endif over/underflowNAMFL0:	.ASCIZ	/$FLO_0/	; nom floppy 0NAMFL1:	.ASCIZ	/$FLO_1/	; nom floppy 1	.EVEN	.END	START